import{_ as e,c as a,o as t,f as i}from"./chunks/framework.BOAZPCR7.js";const m=JSON.parse('{"title":"Functional and antigenic constraints on the Nipah virus fusion protein","description":"","frontmatter":{"layout":"paper","title":"Functional and antigenic constraints on the Nipah virus fusion protein","date":"2025-10-15","authors":["Brendan B Larsen","Sheri Harari","Risako Gen","Cameron Stewart","David Veesler","Jesse D Bloom"],"journal":"bioRxiv","doi":"10.1101/2025.10.15.682664","link":"https://doi.org/10.1101/2025.10.15.682664","image":"/assets/papers/2025_larsen_f.jpg","keywords":["Nipah","Deep mutational scanning","Pseudovirus"],"selected":true,"head":[["link",{"rel":"canonical","href":"https://jbloomlab.org/papers/2025_larsen_f.html"}]]},"headers":[],"relativePath":"papers/2025_larsen_f.md","filePath":"papers/2025_larsen_f.md"}'),n={name:"papers/2025_larsen_f.md"},r=i('<h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Nipah virus is a highly pathogenic virus in the family <em>Paramyxoviridae</em> that utilizes two distinct surface glycoproteins to infect cells. The receptor-binding protein (RBP) binds host receptors whereas the fusion protein (F) merges viral and host membranes. Here, we use non-replicative pseudoviruses to safely measure the effects of all F single amino-acid residue mutations on its cell entry function and neutralization by monoclonal antibodies. We compare mutational tolerance in F with previous experimental measurements for RBP and show that F is much more functionally constrained than the RBP. We also identify mutationally intolerant sites on the F trimer surface and core that are critical for proper function, and describe mutations that are candidates for stabilizing F in the prefusion conformation for vaccine design. We quantify how F mutations affect neutralization by six monoclonal antibodies, and show that the magnitude of mutational effects on neutralization varies among antibodies. Our measurements of mutational effects on Nipah virus F predict the ability of the antibodies to neutralize the related Hendra virus. Overall, our work defines the functional and antigenic constraints on the F protein from an important zoonotic virus.</p><h2 id="interactive-visualizations" tabindex="-1">Interactive visualizations <a class="header-anchor" href="#interactive-visualizations" aria-label="Permalink to &quot;Interactive visualizations&quot;">​</a></h2><p>The results described in this paper can be interactively visualized at <a href="https://dms-vep.org/Nipah_Malaysia_F_DMS/" target="_blank" rel="noreferrer">https://dms-vep.org/Nipah_Malaysia_F_DMS/</a></p>',4),o=[r];function s(l,c,h,u,d,p){return t(),a("div",null,o)}const _=e(n,[["render",s]]);export{m as __pageData,_ as default};
